# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib3  # To perform http request
http = urllib3.PoolManager()


def lambda_handler(event, context):
    print("event : {}".format(json.dumps(event)))

    try:
        enrichmentUrl = event['headers']['X-Enrich-URL']  # Request header key to fetch content from enrichment service

        # Making a http request to get the data from enrichment service.
        response = http.request('GET', enrichmentUrl)
        
        # If successfull, return the response in the body for edge lambda to forward to client.
        body = {
            'headers': event['headers'],  # We don't want to lose the original headers with this
            "body": json.loads(response.data).encode('UTF-8')  
        }
        return {'statusCode': 200, 'headers': {}, 'body': body}

    except Exception as e:

        # This is the default response in case of failure.
        # In future we can send the error details back to origin server with a new header X-EnrichmentError
        return {
            "statusCode": 502,
            "body": json.dumps({
                'error': 'An error occurred. Please check the enrichment URL in X-Enrich-URL request headers.'
            })
        }